#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=205;
const ll inf=1e17;
int n,p,tt,s,t,fir[N];
struct node
{
	int v,w,fan;
};
ll lev[N];
vector<node> g[N];
struct edge
{
	ll u,v,w;
} e[40005];
void add(int u,int v,ll w)
{
	g[u].push_back(node{v,w,g[v].size()});
	g[v].push_back(node{u,0,g[u].size()-1});
}
bool bfs()
{
	for(int i=1;i<=N-3;i++)
	{
		lev[i]=inf;
		fir[i]=0;
	}
	queue<int> q;
	q.push(s);
	lev[s]=0;
	while(!q.empty())
	{
		int u=q.front();
		q.pop();
		for(int i=0;i<g[u].size();i++)
		{
			ll v=g[u][i].v,w=g[u][i].w;
			if((w>0)&&(lev[v]==inf))
			{
				q.push(v);
				lev[v]=lev[u]+1;
				if(v==t) return 1;
			}
		}
	}
	return 0;
}
ll dfs(int u,ll mn)//mn是目前找到的这条增广路的min 
{
	if(u==t) return mn;
	ll ans=0;
	for(int i=fir[u];i<g[u].size();i++)
	{
		fir[u]=i;
		ll v=g[u][i].v,w=g[u][i].w;
		if((w>0)&&(lev[v]==lev[u]+1))
		{
			ll num=dfs(v,min(mn,(ll)w));
			if(num==0) lev[v]=inf;
			g[u][i].w-=num;
			g[v][g[u][i].fan].w+=num;//反向边
			ans+=num;
			mn-=num;
		}
	}
	return ans;
}
bool check(int mid)
{
	for(int i=1;i<=n;i++) g[i].clear();
	for(int i=1;i<=p;i++)
	{
		if(e[i].w<=mid) add(e[i].u,e[i].v,1),add(e[i].v,e[i].u,1);
	}
	ll ans=0;
	while(bfs())
	{
		ans+=dfs(s,inf);
	}
	return ans>=tt;
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n>>p>>tt;
	s=1,t=n;
	ll l=1e6,r=1,mid;
	for(int i=1;i<=p;i++)
	{
		ll u,v,w;
		cin>>u>>v>>w;
		r=max(r,w);
		l=min(l,w);
		e[i]=edge{u,v,w};
	}
	while(l<=r)
	{
		mid=(l+r)/2;
		if(check(mid)) r=mid-1;
		else l=mid+1;
	}
	cout<<r+1;
	return 0;
}
